import{_ as n,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Plattformfunktionen: Modelle und Kontingente | opencode-antigravity-auth","description":"Erfahren Sie mehr über die Modelle und das doppelte Kontingentsystem von Antigravity Auth. Beherrschen Sie die Modellauswahl, Thinking-Konfiguration und Google Search-Methoden.","frontmatter":{"title":"Plattformfunktionen: Modelle und Kontingente | opencode-antigravity-auth","sidebarTitle":"Doppeltes Kontingentsystem freischalten","subtitle":"Plattformfunktionen: Modelle und Kontingente","description":"Erfahren Sie mehr über die Modelle und das doppelte Kontingentsystem von Antigravity Auth. Beherrschen Sie die Modellauswahl, Thinking-Konfiguration und Google Search-Methoden.","order":2},"headers":[],"relativePath":"de/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"de/NoeFabris/opencode-antigravity-auth/platforms/index.md"}'),r={name:"de/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function o(l,e,d,s,u,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="plattformfunktionen" tabindex="-1">Plattformfunktionen <a class="header-anchor" href="#plattformfunktionen" aria-label="Permalink to &quot;Plattformfunktionen&quot;">​</a></h1><p>Dieses Kapitel hilft Ihnen, die von Antigravity Auth unterstützten Modelle, das Kontingentsystem und die Plattformmerkmale besser zu verstehen. Sie lernen, wie Sie das geeignete Modell auswählen, Thinking-Fähigkeiten konfigurieren, Google Search aktivieren und die Kontingentnutzung maximieren.</p><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Vor dem Start</p><p>Bevor Sie dieses Kapitel studieren, stellen Sie sicher, dass Sie Folgendes abgeschlossen haben:</p><ul><li><a href="./../start/quick-install/">Schnellinstallation</a>: Installation des Plugins und erste Authentifizierung</li><li><a href="./../start/first-request/">Erste Anfrage</a>: Erfolgreiche Durchführung der ersten Modellanfrage</li></ul></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Lernen Sie in der folgenden Reihenfolge, um die Plattformfunktionen schrittweise zu beherrschen:</p><h3 id="_1-verfugbare-modelle" tabindex="-1">1. <a href="./available-models/">Verfügbare Modelle</a> <a class="header-anchor" href="#_1-verfugbare-modelle" aria-label="Permalink to &quot;1. [Verfügbare Modelle](./available-models/)&quot;">​</a></h3><p>Erfahren Sie mehr über alle verfügbaren Modelle und ihre Variantenkonfigurationen</p><ul><li>Lernen Sie Claude Opus 4.5, Sonnet 4.5 und Gemini 3 Pro/Flash kennen</li><li>Verstehen Sie die Modellverteilung zwischen den beiden Kontingentpools von Antigravity und Gemini CLI</li><li>Beherrschen Sie die Verwendung des <code>--variant</code>-Parameters</li></ul><h3 id="_2-doppeltes-kontingentsystem" tabindex="-1">2. <a href="./dual-quota-system/">Doppeltes Kontingentsystem</a> <a class="header-anchor" href="#_2-doppeltes-kontingentsystem" aria-label="Permalink to &quot;2. [Doppeltes Kontingentsystem](./dual-quota-system/)&quot;">​</a></h3><p>Verstehen Sie die Funktionsweise des doppelten Kontingentpools von Antigravity und Gemini CLI</p><ul><li>Erfahren Sie, wie jedes Konto über zwei unabhängige Gemini-Kontingentpools verfügt</li><li>Aktivieren Sie die automatische Fallback-Konfiguration, um das Kontingent zu verdoppeln</li><li>Geben Sie explizit an, welches Modell welchen Kontingentpool verwendet</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>Aktivieren Sie Google Search für Gemini-Modelle, um die Faktengenauigkeit zu verbessern</p><ul><li>Ermöglichen Sie Gemini die Suche nach Echtzeit-Netzwerkinformationen</li><li>Regulieren Sie den Suchschwellenwert, um die Suchhäufigkeit zu steuern</li><li>Wählen Sie die geeignete Konfiguration basierend auf den Aufgabenanforderungen</li></ul><h3 id="_4-thinking-modelle" tabindex="-1">4. <a href="./thinking-models/">Thinking-Modelle</a> <a class="header-anchor" href="#_4-thinking-modelle" aria-label="Permalink to &quot;4. [Thinking-Modelle](./thinking-models/)&quot;">​</a></h3><p>Beherrschen Sie die Konfiguration und Verwendung von Claude- und Gemini 3 Thinking-Modellen</p><ul><li>Konfigurieren Sie das Thinking-Budget von Claude</li><li>Verwenden Sie den Thinking-Level von Gemini 3 (minimal/low/medium/high)</li><li>Verstehen Sie Interleaved Thinking und Strategien zur Aufbewahrung von Thinking-Blöcken</li></ul><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie mit folgenden Themen fortfahren:</p><ul><li><a href="./../advanced/multi-account-setup/">Multi-Konto-Konfiguration</a>: Konfigurieren Sie mehrere Google-Konten, um Kontingent-Pooling und Lastausgleich zu implementieren</li><li><a href="./../advanced/account-selection-strategies/">Kontoauswahlstrategien</a>: Beherrschen Sie die Best Practices für die drei Strategien sticky, round-robin und hybrid</li><li><a href="./../advanced/configuration-guide/">Konfigurationsleitfaden</a>: Beherrschen Sie alle Konfigurationsoptionen und passen Sie das Plugin-Verhalten nach Bedarf an</li></ul>',21)])])}const f=n(r,[["render",o]]);export{c as __pageData,f as default};
